message.content:
@startuml
left to right direction
skinparam packageStyle rectangle
skinparam class {
  BackgroundColor White
  BorderColor Black
  FontColor Black
}

package "aggregate+ Product" {
  class Product {
    <<entity>>
    <<root>>
    -uniqueInternalCode
  }

  class ShortDescription {
    <<value object>>
  }

  class LongDescription {
    <<value object>>
  }

  class TechnicalDescription {
    <<value object>>
  }

  class Barcode {
    <<value object>>
  }

  class ProductionCode {
    <<value object>>
  }

  class PriceWithoutVAT {
    <<value object>>
  }

  class PriceWithVAT {
    <<value object>>
  }

  class Reference {
    <<value object>>
  }

  class Weight {
    <<value object>>
  }

  class Volume {
    <<value object>>
  }

  class Photo {
    <<value object>>
  }

  class BrandName {
    <<value object>>
  }
}

package "aggregate+ Category" {
  class Category {
    <<entity>>
    -AlphanumericCode
  }

  class Description {
    <<value object>>
  }

  class SuperCategory {
    <<value object>>
  }
}

Product --> ShortDescription : characterized by
Product --> LongDescription : characterized by
Product --> TechnicalDescription : characterized by
Product --> Barcode : identified by
Product --> ProductionCode : identified by
Product --> PriceWithoutVAT : identified by
Product --> PriceWithVAT : identified by
Product --> Reference : identified by
Product --> Weight : characterized by
Product --> Volume : characterized by
Product --> Photo : described by
Product --> BrandName : made by

Product --> Category : organized by

Category --> Category : belongs to
Category --> AlphanumericCode : identified by
Category --> Description : characterized by
Category --> SuperCategory : belongs to

@enduml
